package com.banking.secure.validation;

import java.math.BigDecimal;
import java.util.regex.Pattern;

public class InputValidator {
    private static final Pattern ACCOUNT_NUMBER_PATTERN = Pattern.compile("^[0-9]{10,16}$");
    private static final Pattern AMOUNT_PATTERN = Pattern.compile("^[0-9]+(\\.[0-9]{1,2})?$");
    private static final Pattern DESCRIPTION_PATTERN = Pattern.compile("^[a-zA-Z0-9\\s\\-_.,']{0,200}$");
    private static final Pattern PIN_PATTERN = Pattern.compile("^[0-9]{4,8}$");
    private static final BigDecimal MAX_TRANSACTION_AMOUNT = new BigDecimal("1000000.00");
    private static final BigDecimal MIN_TRANSACTION_AMOUNT = new BigDecimal("0.01");

    public static class ValidationResult {
        public boolean isValid;
        public String errorMessage;

        public ValidationResult(boolean isValid, String errorMessage) {
            this.isValid = isValid;
            this.errorMessage = errorMessage;
        }

        public static ValidationResult valid() {
            return new ValidationResult(true, null);
        }

        public static ValidationResult invalid(String message) {
            return new ValidationResult(false, message);
        }
    }

    public static ValidationResult validateAccountNumber(String accountNumber) {
        if (accountNumber == null || accountNumber.trim().isEmpty()) {
            return ValidationResult.invalid("Account number is required");
        }
        if (!ACCOUNT_NUMBER_PATTERN.matcher(accountNumber.trim()).matches()) {
            return ValidationResult.invalid("Invalid account number format");
        }
        return ValidationResult.valid();
    }

    public static ValidationResult validateAmount(String amountStr) {
        if (amountStr == null || amountStr.trim().isEmpty()) {
            return ValidationResult.invalid("Amount is required");
        }
        if (!AMOUNT_PATTERN.matcher(amountStr.trim()).matches()) {
            return ValidationResult.invalid("Invalid amount format");
        }
        try {
            BigDecimal amount = new BigDecimal(amountStr.trim());
            if (amount.compareTo(MIN_TRANSACTION_AMOUNT) < 0) {
                return ValidationResult.invalid("Amount must be at least $0.01");
            }
            if (amount.compareTo(MAX_TRANSACTION_AMOUNT) > 0) {
                return ValidationResult.invalid("Amount exceeds maximum transaction limit");
            }
        } catch (NumberFormatException e) {
            return ValidationResult.invalid("Invalid amount");
        }
        return ValidationResult.valid();
    }

    public static ValidationResult validateDescription(String description) {
        if (description == null || description.trim().isEmpty()) {
            return ValidationResult.valid(); // Description is optional
        }
        if (!DESCRIPTION_PATTERN.matcher(description).matches()) {
            return ValidationResult.invalid("Description contains invalid characters");
        }
        return ValidationResult.valid();
    }

    public static ValidationResult validatePin(String pin) {
        if (pin == null || pin.trim().isEmpty()) {
            return ValidationResult.invalid("PIN is required");
        }
        if (!PIN_PATTERN.matcher(pin.trim()).matches()) {
            return ValidationResult.invalid("PIN must be 4-8 digits");
        }
        // Check for simple patterns
        if (isSequential(pin) || isRepeating(pin)) {
            return ValidationResult.invalid("PIN is too simple. Choose a more secure PIN");
        }
        return ValidationResult.valid();
    }

    private static boolean isSequential(String pin) {
        boolean ascending = true;
        boolean descending = true;
        for (int i = 1; i < pin.length(); i++) {
            if (pin.charAt(i) - pin.charAt(i - 1) != 1) ascending = false;
            if (pin.charAt(i - 1) - pin.charAt(i) != 1) descending = false;
        }
        return ascending || descending;
    }

    private static boolean isRepeating(String pin) {
        char first = pin.charAt(0);
        for (int i = 1; i < pin.length(); i++) {
            if (pin.charAt(i) != first) return false;
        }
        return true;
    }

    public static String sanitize(String input) {
        if (input == null) return null;
        return input.replaceAll("[<>\"';(){}]", "").trim();
    }
}


