package com.banking.secure.audit;

import android.content.Context;
import android.util.Log;

import com.banking.secure.SecurityManager;

import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.Locale;
import java.util.concurrent.ConcurrentLinkedQueue;

public class AuditLogger {
    private static final String TAG = "AuditLogger";

    public enum AuditEventType {
        LOGIN_SUCCESS, LOGIN_FAILURE, LOGOUT,
        TRANSACTION_INITIATED, TRANSACTION_COMPLETED, TRANSACTION_FAILED,
        BALANCE_INQUIRY, ACCOUNT_LOCKED, SESSION_EXPIRED,
        SECURITY_VIOLATION, PIN_CHANGED
    }

    private final SecurityManager securityManager;
    private final ConcurrentLinkedQueue<AuditEntry> auditQueue;

    public AuditLogger(Context context, SecurityManager securityManager) {
        this.securityManager = securityManager;
        this.auditQueue = new ConcurrentLinkedQueue<>();
    }

    public void log(AuditEventType eventType, String accountId, String details) {
        AuditEntry entry = new AuditEntry(
                System.currentTimeMillis(),
                eventType,
                accountId != null ? maskAccountId(accountId) : "SYSTEM",
                details
        );
        auditQueue.offer(entry);
        // In production, this would be sent to a secure server
        Log.i(TAG, "AUDIT: " + entry.toString());
    }

    public void logSecurityViolation(String description) {
        log(AuditEventType.SECURITY_VIOLATION, null, description);
    }

    private String maskAccountId(String accountId) {
        if (accountId.length() <= 4) return "****";
        return "****" + accountId.substring(accountId.length() - 4);
    }

    private static class AuditEntry {
        long timestamp;
        AuditEventType eventType;
        String accountIdentifier;
        String details;

        AuditEntry(long timestamp, AuditEventType eventType,
                   String accountIdentifier, String details) {
            this.timestamp = timestamp;
            this.eventType = eventType;
            this.accountIdentifier = accountIdentifier;
            this.details = details;
        }

        @Override
        public String toString() {
            SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS'Z'",
                    Locale.US);
            return String.format("[%s] %s | Account: %s | %s",
                    sdf.format(new Date(timestamp)),
                    eventType.name(),
                    accountIdentifier,
                    details);
        }
    }
}


