package com.banking.secure.transaction;

import android.content.Context;

import com.banking.secure.SecurityManager;
import com.banking.secure.audit.AuditLogger;
import com.banking.secure.model.Account;
import com.banking.secure.model.Transaction;
import com.banking.secure.model.TransactionResult;
import com.banking.secure.validation.InputValidator;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

public class TransactionProcessor {
    private static final String TAG = "TransactionProcessor";
    private static final BigDecimal DAILY_TRANSFER_LIMIT = new BigDecimal("50000.00");

    private final SecurityManager securityManager;
    private final AuditLogger auditLogger;
    private final Map<String, Account> accounts; // In production: database/server
    private final Map<String, List<Transaction>> transactionHistory;
    private final Set<String> processedIdempotencyKeys;
    private final Map<String, ReentrantLock> accountLocks;
    private final Map<String, BigDecimal> dailyTransferTotals;

    public TransactionProcessor(Context context) {
        this.securityManager = new SecurityManager(context);
        this.auditLogger = new AuditLogger(context, securityManager);
        this.accounts = new ConcurrentHashMap<>();
        this.transactionHistory = new ConcurrentHashMap<>();
        this.processedIdempotencyKeys = ConcurrentHashMap.newKeySet();
        this.accountLocks = new ConcurrentHashMap<>();
        this.dailyTransferTotals = new ConcurrentHashMap<>();

        performSecurityChecks();
    }

    private void performSecurityChecks() {
        if (securityManager.isDeviceRooted()) {
            auditLogger.logSecurityViolation("Rooted device detected");
            // In production, you might want to restrict functionality
        }
        if (securityManager.isEmulator()) {
            auditLogger.logSecurityViolation("Emulator detected");
        }
    }

    public SecurityManager getSecurityManager() {
        return securityManager;
    }

    public AuditLogger getAuditLogger() {
        return auditLogger;
    }

    public boolean authenticateUser(String accountId, String pin) {
        if (securityManager.isAccountLocked(accountId)) {
            auditLogger.log(AuditLogger.AuditEventType.ACCOUNT_LOCKED, accountId,
                    "Login attempt on locked account");
            return false;
        }

        InputValidator.ValidationResult pinValidation = InputValidator.validatePin(pin);
        if (!pinValidation.isValid) {
            return false;
        }

        String storedHash = securityManager.getSecure("pin_hash_" + accountId);
        String storedSalt = securityManager.getSecure("pin_salt_" + accountId);

        if (storedHash == null || storedSalt == null) {
            return false;
        }

        String computedHash = securityManager.hashPin(pin, storedSalt);

        if (constantTimeEquals(storedHash, computedHash)) {
            securityManager.resetFailedAttempts(accountId);
            securityManager.generateSessionToken();
            auditLogger.log(AuditLogger.AuditEventType.LOGIN_SUCCESS, accountId,
                    "User authenticated successfully");
            return true;
        } else {
            securityManager.recordFailedAttempt(accountId);
            auditLogger.log(AuditLogger.AuditEventType.LOGIN_FAILURE, accountId,
                    "Invalid PIN attempt");
            return false;
        }
    }

    // Constant-time comparison to prevent timing attacks
    private boolean constantTimeEquals(String a, String b) {
        if (a == null || b == null) return false;
        byte[] aBytes = a.getBytes();
        byte[] bBytes = b.getBytes();
        if (aBytes.length != bBytes.length) return false;
        int result = 0;
        for (int i = 0; i < aBytes.length; i++) {
            result |= aBytes[i] ^ bBytes[i];
        }
        return result == 0;
    }

    public void registerAccount(String accountId, String pin, String accountNumber,
                                String holderName, BigDecimal initialBalance, String currency) {
        InputValidator.ValidationResult pinResult = InputValidator.validatePin(pin);
        if (!pinResult.isValid) {
            throw new IllegalArgumentException(pinResult.errorMessage);
        }

        String salt = securityManager.generateSalt();
        String pinHash = securityManager.hashPin(pin, salt);

        securityManager.storeSecure("pin_hash_" + accountId, pinHash);
        securityManager.storeSecure("pin_salt_" + accountId, salt);

        Account account = new Account(accountId, accountNumber, holderName,
                initialBalance, "CHECKING", currency);
        accounts.put(accountId, account);
        transactionHistory.put(accountId, Collections.synchronizedList(new ArrayList<>()));
        accountLocks.put(accountId, new ReentrantLock(true)); // fair lock
    }

    public TransactionResult processTransfer(String sourceAccountId,
                                              String destinationAccountId,
                                              String amountStr,
                                              String description,
                                              String pin) {
        // Validate session
        if (!securityManager.isSessionValid()) {
            auditLogger.log(AuditLogger.AuditEventType.SESSION_EXPIRED, sourceAccountId,
                    "Transfer attempt with expired session");
            return TransactionResult.failure("SESSION_EXPIRED", "Session has expired. Please log in again.");
        }

        // Re-authenticate for sensitive operation
        if (!authenticateForTransaction(sourceAccountId, pin)) {
            return TransactionResult.failure("AUTH_FAILED", "Authentication failed for transaction");
        }

        // Validate inputs
        InputValidator.ValidationResult amountValidation = InputValidator.validateAmount(amountStr);
        if (!amountValidation.isValid) {
            return TransactionResult.failure("INVALID_AMOUNT", amountValidation.errorMessage);
        }

        InputValidator.ValidationResult descValidation = InputValidator.validateDescription(description);
        if (!descValidation.isValid) {
            return TransactionResult.failure("INVALID_DESCRIPTION", descValidation.errorMessage);
        }

        BigDecimal amount = new BigDecimal(amountStr).setScale(2, RoundingMode.HALF_UP);
        String sanitizedDescription = InputValidator.sanitize(description);

        // Check daily limit
        BigDecimal dailyTotal = dailyTransferTotals.getOrDefault(sourceAccountId, BigDecimal.ZERO);
        if (dailyTotal.add(amount).compareTo(DAILY_TRANSFER_LIMIT) > 0) {
            auditLogger.log(AuditLogger.AuditEventType.TRANSACTION_FAILED, sourceAccountId,
                    "Daily transfer limit exceeded");
            return TransactionResult.failure("DAILY_LIMIT_EXCEEDED",
                    "Daily transfer limit exceeded. Remaining: $" +
                            DAILY_TRANSFER_LIMIT.subtract(dailyTotal).toPlainString());
        }

        // Create transaction
        Transaction transaction = new Transaction(sourceAccountId, destinationAccountId,
                amount, "USD", Transaction.TransactionType.TRANSFER, sanitizedDescription);

        // Check idempotency
        if (processedIdempotencyKeys.contains(transaction.getIdempotencyKey())) {
            return TransactionResult.failure("DUPLICATE_TRANSACTION",
                    "This transaction has already been processed");
        }

        auditLogger.log(AuditLogger.AuditEventType.TRANSACTION_INITIATED, sourceAccountId,
                "Transfer of $" + amount.toPlainString() + " initiated. Ref: " +
                        transaction.getReferenceNumber());

        // Acquire locks in consistent order to prevent deadlock
        String firstLock = sourceAccountId.compareTo(destinationAccountId) < 0
                ? sourceAccountId : destinationAccountId;
        String secondLock = sourceAccountId.compareTo(destinationAccountId) < 0
                ? destinationAccountId : sourceAccountId;

        ReentrantLock lock1 = accountLocks.get(firstLock);
        ReentrantLock lock2 = accountLocks.get(secondLock);

        if (lock1 == null || lock2 == null) {
            return TransactionResult.failure("ACCOUNT_NOT_FOUND", "One or more accounts not found");
        }

        lock1.lock();
        try {
            lock2.lock();
            try {
                return executeTransfer(transaction, amount, sourceAccountId, destinationAccountId);
            } finally {
                lock2.unlock();
            }
        } finally {
            lock1.unlock();
        }
    }

    private TransactionResult executeTransfer(Transaction transaction, BigDecimal amount,
                                               String sourceAccountId, String destinationAccountId) {
        Account source = accounts.get(sourceAccountId);
        Account destination = accounts.get(destinationAccountId);

        if (source == null || destination == null) {
            transaction.setStatus(Transaction.TransactionStatus.FAILED);
            return TransactionResult.failure("ACCOUNT_NOT_FOUND", "Account not found");
        }

        if (!source.isActive() || !destination.isActive()) {
            transaction.setStatus(Transaction.TransactionStatus.FAILED);
            return TransactionResult.failure("ACCOUNT_INACTIVE", "One or more accounts is inactive");
        }

        // Check sufficient balance
        if (source.getBalance().compareTo(amount) < 0) {
            transaction.setStatus(Transaction.TransactionStatus.FAILED);
            auditLogger.log(AuditLogger.AuditEventType.TRANSACTION_FAILED, sourceAccountId,
                    "Insufficient funds. Ref: " + transaction.getReferenceNumber());
            return TransactionResult.failure("INSUFFICIENT_FUNDS", "Insufficient balance");
        }

        // Process transfer
        transaction.setStatus(Transaction.TransactionStatus.PROCESSING);

        BigDecimal newSourceBalance = source.getBalance().subtract(amount);
        BigDecimal newDestBalance = destination.getBalance().add(amount);

        source.setBalance(newSourceBalance);
        destination.setBalance(newDestBalance);

        transaction.setStatus(Transaction.TransactionStatus.COMPLETED);

        // Record transaction
        processedIdempotencyKeys.add(transaction.getIdempotencyKey());
        transactionHistory.get(sourceAccountId).add(transaction);
        if (transactionHistory.containsKey(destinationAccountId)) {
            transactionHistory.get(destinationAccountId).add(transaction);
        }

        // Update daily total
        BigDecimal currentDaily = dailyTransferTotals.getOrDefault(sourceAccountId, BigDecimal.ZERO);
        dailyTransferTotals.put(sourceAccountId, currentDaily.add(amount));

        auditLogger.log(AuditLogger.AuditEventType.TRANSACTION_COMPLETED, sourceAccountId,
                "Transfer of $" + amount.toPlainString() + " completed. Ref: " +
                        transaction.getReferenceNumber() + ". New balance: $" +
                        newSourceBalance.toPlainString());

        return TransactionResult.success(transaction.getTransactionId(),
                transaction.getReferenceNumber(), newSourceBalance);
    }

    private boolean authenticateForTransaction(String accountId, String pin) {
        String storedHash = securityManager.getSecure("pin_hash_" + accountId);
        String storedSalt = securityManager.getSecure("pin_salt_" + accountId);
        if (storedHash == null || storedSalt == null) return false;
        String computedHash = securityManager.hashPin(pin, storedSalt);
        return constantTimeEquals(storedHash, computedHash);
    }

    public BigDecimal getBalance(String accountId) {
        if (!securityManager.isSessionValid()) {
            throw new SecurityException("Session expired");
        }
        Account account = accounts.get(accountId);
        if (account == null) {
            throw new IllegalArgumentException("Account not found");
        }
        auditLogger.log(AuditLogger.AuditEventType.BALANCE_INQUIRY, accountId,
                "Balance inquiry performed");
        return account.getBalance();
    }

    public String getFormattedBalance(String accountId) {
        BigDecimal balance = getBalance(accountId);
        Account account = accounts.get(accountId);
        String currency = account != null ? account.getCurrency() : "USD";
        return String.format("$%,.2f %s", balance, currency);
    }

    public Account getAccountInfo(String accountId) {
        if (!securityManager.isSessionValid()) {
            throw new SecurityException("Session expired");
        }
        return accounts.get(accountId);
    }

    public List<Transaction> getTransactionHistory(String accountId) {
        if (!securityManager.isSessionValid()) {
            throw new SecurityException("Session expired");
        }
        List<Transaction> history = transactionHistory.get(accountId);
        if (history == null) {
            return new ArrayList<>();
        }
        return new ArrayList<>(history); // Return defensive copy
    }

    public void logout(String accountId) {
        securityManager.invalidateSession();
        auditLogger.log(AuditLogger.AuditEventType.LOGOUT, accountId, "User logged out");
    }
}


// ==================== BalanceDisplayHelper.java ====================
package com.banking.secure.ui;

import android.content.Context;
import android.view.View;
import android.widget.TextView;

import com.banking.secure.model.Account;
import com.banking.secure.transaction.TransactionProcessor;

import java.math.BigDecimal;
import java.text.NumberFormat;
import java.text.SimpleDateFormat;
import java.util.Currency;
import java.util.Date;
import java.util.Locale;

public class BalanceDisplayHelper {
    private final TransactionProcessor transactionProcessor;
    private boolean isBalanceVisible = false;

    public BalanceDisplayHelper(TransactionProcessor transactionProcessor) {
        this.transactionProcessor = transactionProcessor;
    }

    public void displayBalance(TextView balanceTextView, TextView accountInfoTextView,
                                String accountId) {
        try {
            Account account = transactionProcessor.getAccountInfo(accountId);
            if (account == null) {
                balanceTextView.setText("Account not found");
                return;
            }

            if (isBalanceVisible) {
                NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.US);
                currencyFormat.setCurrency(Currency.getInstance(account.getCurrency()));
                String formattedBalance = currencyFormat.format(account.getBalance());
                balanceTextView.setText(formattedBalance);
            } else {
                balanceTextView.setText("$*,***.** " + account.getCurrency());
            }

            if (accountInfoTextView != null) {
                String info = account.getAccountType() + " - " + account.getMaskedAccountNumber();
                accountInfoTextView.setText(info);
            }
        } catch (SecurityException e) {
            balanceTextView.setText("Session expired. Please log in.");
        }
    }

    public void toggleBalanceVisibility(TextView balanceTextView, TextView accountInfoTextView,
                                         String accountId) {
        isBalanceVisible = !isBalanceVisible;
        displayBalance(balanceTextView, accountInfoTextView, accountId);
    }

    public boolean isBalanceVisible() {
        return isBalanceVisible;
    }

    public void hideBalance() {
        isBalanceVisible = false;
    }

    public static String formatLastUpdated(long timestamp) {
        SimpleDateFormat sdf = new SimpleDateFormat("MMM dd, yyyy 'at' hh:mm a", Locale.US);
        return "Last updated: " + sdf.format(new Date(timestamp));
    }
}


// ==================== MainActivity.java ====================
package com.banking.secure;

import android.app.AlertDialog;
import android.os.Bundle;
import android.text.InputType;
import android.view.View;
import android.view.WindowManager;
import android.widget.Button;
import android.widget.EditText;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import com.banking.secure.model.Transaction;
import com.banking.secure.model.TransactionResult;
import com.banking.secure.transaction.TransactionProcessor;
import com.banking.secure.ui.BalanceDisplayHelper;

import java.math.BigDecimal;
import java.text.SimpleDateFormat;
import java.util.Date;
import java.util.List;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private TransactionProcessor transactionProcessor;
    private BalanceDisplayHelper balanceDisplayHelper;

    private LinearLayout loginLayout;
    private LinearLayout dashboardLayout;

    private EditText etAccountId;
    private EditText etPin;
    private Button btnLogin;

    private TextView tvWelcome;
    private TextView tvBalance;
    private TextView tvAccountInfo;
    private TextView tvLastUpdated;
    private Button btnToggleBalance;
    private Button btnTransfer;
    private Button btnHistory;
    private Button btnLogout;
    private TextView tvTransactionHistory;

    private String currentAccountId;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        // Prevent screenshots and screen recording for security
        getWindow().setFlags(WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE);

        transactionProcessor = new TransactionProcessor(this);
        balanceDisplayHelper = new BalanceDisplayHelper(transactionProcessor);

        setupDemoAccounts();
        buildUI();
        showLoginScreen();
    }

    @Override
    protected void onPause() {
        super.onPause();
        // Hide balance when app goes to background
        balanceDisplayHelper.hideBalance();
        if (tvBalance != null) {
            tvBalance.setText("$*,***.** USD");
        }
    }

    @Override
    protected void onStop() {
        super.onStop();
        // Consider session timeout
    }

    private void setupDemoAccounts() {
        transactionProcessor.registerAccount("user001", "5739",
                "1234567890", "John Doe",
                new BigDecimal("25000.50"), "USD");

        transactionProcessor.registerAccount("user002", "4821",
                "0987654321", "Jane Smith",
                new BigDecimal("15000.00"), "USD");
    }

    private void buildUI() {
        ScrollView scrollView = new ScrollView(this);
        LinearLayout mainLayout = new LinearLayout(this);
        mainLayout.setOrientation(LinearLayout.VERTICAL);
        mainLayout.setPadding(48, 48, 48, 48);

        // Login Layout
        loginLayout = new LinearLayout(this);
        loginLayout.setOrientation(LinearLayout.VERTICAL);

        TextView tvLoginTitle = new TextView(this);
        tvLoginTitle.setText("Secure Banking");
        tvLoginTitle.setTextSize(28);
        tvLoginTitle.setPadding(0, 0, 0, 48);

        etAccountId = new EditText(this);
        etAccountId.setHint("Account ID");
        etAccountId.setInputType(InputType.TYPE_CLASS_TEXT);
        etAccountId.setPadding(24, 24, 24, 24);

        etPin = new EditText(this);
        etPin.setHint("PIN");
        etPin.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_VARIATION_PASSWORD);
        etPin.setPadding(24, 24, 24, 24);

        btnLogin = new Button(this);
        btnLogin.setText("Login");
        btnLogin.setOnClickListener(v -> performLogin());

        loginLayout.addView(tvLoginTitle);
        loginLayout.addView(etAccountId);
        loginLayout.addView(etPin);
        loginLayout.addView(btnLogin);

        // Dashboard Layout
        dashboardLayout = new LinearLayout(this);
        dashboardLayout.setOrientation(LinearLayout.VERTICAL);

        tvWelcome = new TextView(this);
        tvWelcome.setTextSize(22);
        tvWelcome.setPadding(0, 0, 0, 24);

        tvAccountInfo = new TextView(this);
        tvAccountInfo.setTextSize(14);
        tvAccountInfo.setPadding(0, 0, 0, 8);

        tvBalance = new TextView(this);
        tvBalance.setTextSize(32);
        tvBalance.setPadding(0, 0, 0, 8);

        tvLastUpdated = new TextView(this);
        tvLastUpdated.setTextSize(12);
        tvLastUpdated.setPadding(0, 0, 0, 24);

        btnToggleBalance = new Button(this);
        btnToggleBalance.setText("Show Balance");
        btnToggleBalance.setOnClickListener(v -> toggleBalance());

        btnTransfer = new Button(this);
        btnTransfer.setText("Transfer Funds");
        btnTransfer.setOnClickListener(v -> showTransferDialog());

        btnHistory = new Button(this);
        btnHistory.setText("Transaction History");
        btnHistory.setOnClickListener(v -> showTransactionHistory());

        btnLogout = new Button(this);
        btnLogout.setText("Logout");
        btnLogout.setOnClickListener(v -> performLogout());

        tvTransactionHistory = new TextView(this);
        tvTransactionHistory.setTextSize(12);
        tvTransactionHistory.setPadding(0, 24, 0, 0);

        dashboardLayout.addView(tvWelcome);
        dashboardLayout.addView(tvAccountInfo);
        dashboardLayout.addView(tvBalance);
        dashboardLayout.addView(tvLastUpdated);
        dashboardLayout.addView(btnToggleBalance);
        dashboardLayout.addView(btnTransfer);
        dashboardLayout.addView(btnHistory);
        dashboardLayout.addView(btnLogout);
        dashboardLayout.addView(tvTransactionHistory);

        mainLayout.addView(loginLayout);
        mainLayout.addView(dashboardLayout);
        scrollView.addView(mainLayout);
        setContentView(scrollView);
    }

    private void showLoginScreen() {
        loginLayout.setVisibility(View.VISIBLE);
        dashboardLayout.setVisibility(View.GONE);
        etAccountId.setText("");
        etPin.setText("");
    }

    private void showDashboard() {
        loginLayout.setVisibility(View.GONE);
        dashboardLayout.setVisibility(View.VISIBLE);
        refreshDashboard();
    }

    private void performLogin() {
        String accountId = etAccountId.getText().toString().trim();
        String pin = etPin.getText().toString().trim();

        if (accountId.isEmpty() || pin.isEmpty()) {
            Toast.makeText(this, "Please enter account ID and PIN", Toast.LENGTH_SHORT).show();
            return;
        }

        if (transactionProcessor.getSecurityManager().isAccountLocked(accountId)) {
            Toast.makeText(this, "Account is locked due to too many failed attempts. " +
                    "Please try again in 30 minutes.", Toast.LENGTH_LONG).show();
            return;
        }

        if (transactionProcessor.authenticateUser(accountId, pin)) {
            currentAccountId = accountId;
            // Clear sensitive data from UI
            etPin.setText("");
            showDashboard();
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
            etPin.setText("");
        }
    }

    private void refreshDashboard() {
        try {
            var account = transactionProcessor.getAccountInfo(currentAccountId);
            if (account != null) {
                tvWelcome.setText("Welcome, " + account.getAccountHolderName());
                balanceDisplayHelper.displayBalance(tvBalance, tvAccountInfo, currentAccountId);
                tvLastUpdated.setText(BalanceDisplayHelper.formatLastUpdated(account.getLastUpdated()));
                btnToggleBalance.setText(balanceDisplayHelper.isBalanceVisible() ?
                        "Hide Balance" : "Show Balance");
            }
        } catch (SecurityException e) {
            Toast.makeText(this, "Session expired. Please log in again.", Toast.LENGTH_LONG).show();
            showLoginScreen();
        }
    }

    private void toggleBalance() {
        balanceDisplayHelper.toggleBalanceVisibility(tvBalance, tvAccountInfo, currentAccountId);
        btnToggleBalance.setText(balanceDisplayHelper.isBalanceVisible() ?
                "Hide Balance" : "Show Balance");
    }

    private void showTransferDialog() {
        AlertDialog.Builder builder = new AlertDialog.Builder(this);
        builder.setTitle("Transfer Funds");

        LinearLayout dialogLayout = new LinearLayout(this);
        dialogLayout.setOrientation(LinearLayout.VERTICAL);
        dialogLayout.setPadding(48, 24, 48, 24);

        EditText etDestAccount = new EditText(this);
        etDestAccount.setHint("Destination Account ID");
        etDestAccount.setInputType(InputType.TYPE_CLASS_TEXT);

        EditText etAmount = new EditText(this);
        etAmount.setHint("Amount (e.g., 100.00)");
        etAmount.setInputType(InputType.TYPE_CLASS_NUMBER | InputType.TYPE_NUMBER_FLAG_DECIMAL);

        EditText etDescription = new EditText(this);
        etDescription.setHint("Description (optional)");
        etDescription.setInputType(InputType.TYPE_CLASS_TEXT);

        EditText etTransactionPin = new EditText(this);
        etTransactionPin.setHint("Enter PIN to confirm");
        etTransactionPin.setInputType(InputType.TYPE_CLASS_NUMBER |
                InputType.TYPE_NUMBER_VARIATION_PASSWORD);

        dialogLayout.addView(etDestAccount);
        dialogLayout.addView(etAmount);
        dialogLayout.addView(etDescription);
        dialogLayout.addView(etTransactionPin);

        builder.setView(dialogLayout);

        builder.setPositiveButton("Transfer", (dialog, which) -> {
            String destAccount = etDestAccount.getText().toString().trim();
            String amount = etAmount.getText().toString().trim();
            String desc = etDescription.getText().toString().trim();
            String pin = etTransactionPin.getText().toString().trim();

            if (destAccount.isEmpty() || amount.isEmpty() || pin.isEmpty()) {
                Toast.makeText(this, "Please fill in all required fields", Toast.LENGTH_SHORT).show();
                return;
            }

            if (destAccount.equals(currentAccountId)) {
                Toast.makeText(this, "Cannot transfer to same account", Toast.LENGTH_SHORT).show();
                return;
            }

            TransactionResult result = transactionProcessor.processTransfer(
                    currentAccountId, destAccount, amount, desc, pin);

            if (result.isSuccess()) {
                Toast.makeText(this,
                        "Transfer successful!\nRef: " + result.getReferenceNumber() +
                                "\nNew Balance: $" + result.getNewBalance().toPlainString(),
                        Toast.LENGTH_LONG).show();
                refreshDashboard();
            } else {
                Toast.makeText(this,
                        "Transfer failed: " + result.getMessage(),
                        Toast.LENGTH_LONG).show();
            }
        });

        builder.setNegativeButton("Cancel", null);

        AlertDialog dialog = builder.create();
        // Prevent screenshots of the dialog
        dialog.getWindow().setFlags(WindowManager.LayoutParams.FLAG_SECURE,
                WindowManager.LayoutParams.FLAG_SECURE);
        dialog.show();
    }

    private void showTransactionHistory() {
        try {
            List<Transaction> history = transactionProcessor.getTransactionHistory(currentAccountId);

            if (history.isEmpty()) {
                tvTransactionHistory.setText("No transaction history.");
                return;
            }

            StringBuilder sb = new StringBuilder();
            sb.append("=== Transaction History ===\n\n");

            SimpleDateFormat sdf = new SimpleDateFormat("MMM dd, yyyy HH:mm", Locale.US);

            for (int i = history.size() - 1; i >= Math.max(0, history.size() - 20); i--) {
                Transaction tx = history.get(i);
                sb.append(sdf.format(new Date(tx.getTimestamp()))).append("\n");
                sb.append(tx.getType().name()).append(" | ");
                sb.append("$").append(tx.getAmount().toPlainString()).append("\n");
                sb.append("Status: ").append(tx.getStatus().name()).append("\n");
                sb.append("Ref: ").append(tx.getReferenceNumber()).append("\n");
                if (tx.getDescription() != null && !tx.getDescription().isEmpty()) {
                    sb.append("Desc: ").append(tx.getDescription()).append("\n");
                }
                sb.append("─────────────────\n");
            }

            tvTransactionHistory.setText(sb.toString());
        } catch (SecurityException e) {
            Toast.makeText(this, "Session expired. Please log in again.", Toast.LENGTH_LONG).show();
            showLoginScreen();
        }
    }

    private void performLogout() {
        transactionProcessor.logout(currentAccountId);
        balanceDisplayHelper.hideBalance();
        currentAccountId = null;
        tvTransactionHistory.setText("");
        showLoginScreen();
        Toast.makeText(this, "Logged out successfully", Toast.LENGTH_SHORT).show();
    }

    @Override
    protected void onDestroy() {
        super.onDestroy();
        if (currentAccountId != null) {
            transactionProcessor.logout(currentAccountId);
        }
    }
}